test('should cache results for same arguments', () => {
  let calls = 0;
  const fn = memoize((x) => {
    calls++;
    return x * 2;
  });

  expect(fn(5)).toBe(10);
  expect(fn(5)).toBe(10);
  expect(calls).toBe(1);
});

test('should work with object arguments', () => {
  let calls = 0;
  const fn = memoize((obj) => {
    calls++;
    return obj.value * 2;
  });

  const obj = {value: 5};
  expect(fn(obj)).toBe(10);
  expect(fn(obj)).toBe(10);
  expect(calls).toBe(1);
});

