function memoize(fn) {
  const cache = new Map();

  return function(...args) {
    // Generate cache key from arguments
    let key;

    if (args.length === 1) {
      // Single argument - use directly as key
      key = args[0];
    } else {
      // Multiple arguments - create composite key
      key = JSON.stringify(args);
    }

    if (cache.has(key)) {
      return cache.get(key);
    }

    const result = fn.apply(this, args);
    cache.set(key, result);

    return result;
  };
}

module.exports = memoize;
EOF

